   350→                exp.end_date && exp.end_date !== 'Present' ? new Date(exp.end_date.length === 4 ? exp.end_date + '-01-01' : exp.end_date + '-01') : null,
   351→                exp.is_current || exp.end_date === 'Present',
   352→                exp.description || null,
   353→                JSON.stringify(exp.achievements || []),
   354→                JSON.stringify(exp.skills_used || []),
   355→                i
   356→              ]);
   357→              applySummary.experience++;
   358→            }
   359→          }
   360→
   361→          // 3. Apply education (with dedup: skip if same institution+degree exists)
   362→          if (parsedData.education && Array.isArray(parsedData.education)) {
   363→            for (let i = 0; i < parsedData.education.length; i++) {
   364→              const edu = parsedData.education[i];
   365→              if (!edu.institution) continue;
   366→
   367→              // Check for duplicate
   368→              const existing = await pool.query(
   369→                `SELECT id FROM education WHERE user_id = $1 AND LOWER(institution) = LOWER($2) AND LOWER(COALESCE(degree, '')) = LOWER(COALESCE($3, ''))`,
   370→                [req.user.id, edu.institution, edu.degree || '']
   371→              );
   372→              if (existing.rows.length > 0) continue;
   373→
   374→              await pool.query(`
