   383→                edu.end_date && edu.end_date !== 'Present' ? new Date(edu.end_date + '-01-01') : null,
   384→                edu.gpa || null,
   385→                JSON.stringify(edu.achievements || []),
   386→                i
   387→              ]);
   388→              applySummary.education++;
   389→            }
   390→          }
   391→
   392→          // 4. Apply skills (upsert — won't duplicate due to UNIQUE constraint)
   393→          if (parsedData.skills && Array.isArray(parsedData.skills)) {
   394→            for (const skill of parsedData.skills) {
   395→              if (!skill.name) continue;
   396→              try {
   397→                // Coerce string level names to integers
   398→                let skillLevel = skill.level || 3;
   399→                if (typeof skillLevel === 'string') {
   400→                  const lvlMap = { 'beginner': 1, 'basic': 2, 'intermediate': 3, 'advanced': 4, 'expert': 5 };
   401→                  skillLevel = lvlMap[skillLevel.toLowerCase()] || parseInt(skillLevel, 10) || 3;
   402→                }
   403→                skillLevel = Math.max(1, Math.min(5, parseInt(skillLevel, 10) || 3));
   404→                await pool.query(`
   405→                  INSERT INTO candidate_skills (user_id, skill_name, category, level)
   406→                  VALUES ($1, $2, $3, $4)
   407→                  ON CONFLICT (user_id, skill_name) DO UPDATE SET
   408→                    category = COALESCE(NULLIF($3, ''), candidate_skills.category),
   409→                    level = GREATEST(candidate_skills.level, $4)
   410→                `, [req.user.id, skill.name, skill.category || 'technical', skillLevel]);
   411→                applySummary.skills++;
   412→              } catch (skillErr) {
   413→                console.error('Skip skill insert:', skillErr.message);
   414→              }
   415→            }
   416→          }
   417→
   418→          parsedData._applySummary = applySummary;
   419→          console.log(`Auto-applied resume data for user ${req.user.id}:`, applySummary);
   420→        } catch (applyErr) {
