      screening: { label: 'Screening', color: 'purple', order: 1 },
      shortlisted: { label: 'Shortlisted', color: 'indigo', order: 2 },
      reviewing: { label: 'Reviewing', color: 'amber', order: 3 },
      interviewed: { label: 'Interviewed', color: 'cyan', order: 4 },
