      WHERE ja.job_id = $1
        AND ja.status NOT IN ('withdrawn', 'rejected')
        AND COALESCE(ja.match_score, 0) >= $2
      ORDER BY ja.match_score DESC NULLS LAST, os.total_score DESC NULLS LAST
    `, [jobId, min_score]);

    res.json({
      success: true,
      job: job.rows[0],
      candidates: ranked.rows,
      total: ranked.rows.length
